// Generated by GitHub Copilot
import { useState } from "react";
import { buildApiUrl } from "../utils/api";

function Chatbot({ config, apiBaseUrl }) {
  const chatApiUrl = buildApiUrl("/chat", apiBaseUrl);
  const [open, setOpen] = useState(false);
  const [question, setQuestion] = useState("");
  const [loading, setLoading] = useState(false);
  const [messages, setMessages] = useState([
    {
      role: "assistant",
      content:
        config?.welcomeMessage || "Ask me about Ram's projects, skills, or architecture decisions.",
    },
  ]);

  /**
   * Send a user query through the backend proxy and append the assistant response.
   */
  async function sendMessage() {
    if (!question.trim() || loading) {
      return;
    }

    const userMessage = { role: "user", content: question.trim() };
    const history = messages
      .slice(-4)
      .filter((entry) => entry.role === "user" || entry.role === "assistant")
      .map((entry) => ({
        role: entry.role,
        content: String(entry.content || "").slice(0, 500),
      }));

    setMessages((prev) => [...prev, userMessage]);
    setQuestion("");
    setLoading(true);

    try {
      const response = await fetch(chatApiUrl, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify({
          message: userMessage.content,
          systemPrompt: config?.systemPrompt,
          history,
        }),
      });

      if (!response.ok) {
        throw new Error(`Chat request failed: ${response.status}`);
      }

      const payload = await response.json();
      const content = payload?.reply || payload?.content || "I could not generate a response.";
      setMessages((prev) => [...prev, { role: "assistant", content }]);
    } catch (error) {
      setMessages((prev) => [
        ...prev,
        {
          role: "assistant",
          content: "Chat is temporarily unavailable. Please try again.",
        },
      ]);
      console.error(error);
    } finally {
      setLoading(false);
    }
  }

  return (
    <div className="fixed bottom-4 right-4 z-50">
      {open && (
        <div className="glass-card-strong mb-3 w-[320px] rounded-2xl p-4 md:w-[360px]">
          <h3 className="mb-3 text-sm font-bold text-[rgba(var(--accent-rgb),0.95)]">
            {config?.title || "Dragon Assistant"}
          </h3>
          <div className="mb-3 max-h-64 space-y-2 overflow-y-auto pr-1">
            {messages.map((message, index) => (
              <div
                key={`${message.role}-${index}`}
                className={`rounded-lg p-2 text-sm ${message.role === "user" ? "bg-[rgba(var(--accent-rgb),0.18)] text-[var(--text-primary)]" : "glass-card-soft text-[var(--text-primary)]"
                  }`}
              >
                {message.content}
              </div>
            ))}
          </div>
          <div className="flex gap-2">
            <input
              className="glass-input w-full px-3 py-2 text-sm"
              value={question}
              onChange={(event) => setQuestion(event.target.value)}
              onKeyDown={(event) => {
                if (event.key === "Enter") {
                  sendMessage();
                }
              }}
              placeholder={config?.placeholder || "Ask about projects..."}
              aria-label="Chat question input"
            />
            <button
              type="button"
              onClick={sendMessage}
              disabled={loading}
              className="glass-button-primary rounded-lg px-3 py-2 text-sm font-semibold disabled:opacity-60"
            >
              Send
            </button>
          </div>
        </div>
      )}
      <button
        type="button"
        onClick={() => setOpen((prev) => !prev)}
        className="glass-button-primary rounded-full px-5 py-3 text-sm font-bold"
      >
        {open ? "Close Chat" : "Open Chat"}
      </button>
    </div>
  );
}

export default Chatbot;
